Manacher 演算法線上性時間內求出所有迴文中心的最長迴文串。可用於判斷子串是否為迴文、求最長迴文子串、最短迴文串構造等。模板題為 5. 最長迴文子串。

**C++ 模板**：

```cpp
// Manacher：求每個中心的最長迴文半徑
vector<int> manacher(const string& s) {
    string t = "#";
    for (char c : s) {
        t += c;
        t += '#';
    }
    int n = t.size();
    vector<int> p(n, 0);
    int c = 0, r = 0;
    for (int i = 0; i < n; i++) {
        // 如果 i 在當前回文右邊界內，利用對稱性初始化 p[i]
        if (i < r) {
            p[i] = min(r - i, p[2 * c - i]);
        }
        // 中心擴展：嘗試擴展以 i 為中心的迴文半徑
        while (i - p[i] - 1 >= 0 && i + p[i] + 1 < n && t[i - p[i] - 1] == t[i + p[i] + 1]) {
            p[i]++;
        }
        // 更新迴文右邊界 r 和對應的中心 c
        if (i + p[i] > r) {
            c = i;
            r = i + p[i];
        }
    }
    return p;
}
```

