```cpp
class Solution {
public:
    string longestPalindrome(string s) {
        int bestL = 0, bestLen = 1;
        auto expand = [&](int l, int r) {
            while (l >= 0 && r < (int)s.size() && s[l] == s[r]) l--, r++;
            if (r - l - 1 > bestLen) {
                bestLen = r - l - 1;
                bestL = l + 1;
            }
        };
        for (int i = 0; i < (int)s.size(); ++i) {
            expand(i, i);
            expand(i, i + 1);
        }
        return s.substr(bestL, bestLen);
    }
};
```

