// 字串雜湊（多項式雜湊）
struct StringHash {
    static const long long kMod = 1e9 + 7, kBase = 131;
    vector<long long> h, pw;
    StringHash(const string& s) {
        int n = s.size();
        h.resize(n + 1);
        pw.resize(n + 1);
        h[0] = 0;
        pw[0] = 1;
        for (int i = 0; i < n; i++) {
            h[i + 1] = (h[i] * kBase + s[i]) % kMod;
            pw[i + 1] = pw[i] * kBase % kMod;
        }
    }
    long long get(int l, int r) {
        return (h[r + 1] - h[l] * pw[r - l + 1] % kMod + kMod * 2) % kMod;
    }
};
```

