// AC 自動機 = 字典樹 + KMP fail 指標
struct AhoCorasick {
    vector<array<int, 26>> ch;   // 字典樹的邊
    vector<int> fail;             // fail 指標（類似 KMP 的 next 陣列）
    vector<int> cnt;              // 每個節點結尾的模式串數量

    // 建立新節點
    int newNode() {
        ch.push_back({});
        fail.push_back(0);
        cnt.push_back(0);
        ch.back().fill(0);
        return ch.size() - 1;
    }

    // 建構子：初始化根節點
    AhoCorasick() {
        newNode();
    }

    // 插入模式串到字典樹
    void insert(const string& s) {
        int cur = 0;
        for (char c : s) {
            int u = c - 'a';
            // 如果該邊不存在，建立新節點
            if (!ch[cur][u]) {
                ch[cur][u] = newNode();
            }
            cur = ch[cur][u];
        }
        cnt[cur]++;  // 標記模式串結尾
    }

    // 建立 fail 指標（類似 KMP 的預處理）
    void build() {
        queue<int> q;
        // 第一層節點的 fail 指標都指向根節點
        for (int i = 0; i < 26; i++) {
            if (ch[0][i]) {
                q.push(ch[0][i]);
            }
        }
        // BFS 建立 fail 指標
        while (!q.empty()) {
            int u = q.front();
            q.pop();
            for (int i = 0; i < 26; i++) {
                if (ch[u][i]) {
                    // 節點存在：設定 fail 指標並加入佇列
                    fail[ch[u][i]] = ch[fail[u]][i];
                    q.push(ch[u][i]);
                } else {
                    // 節點不存在：直接指向 fail 位置的對應邊（路徑壓縮）
                    ch[u][i] = ch[fail[u]][i];
                }
            }
        }
    }
};
