**C++ 模板**：

```cpp
// 後綴陣列（倍增法 O(n log n)）
vector<int> buildSa(const string& s) {
    int n = s.size();
    vector<int> sa(n), rank(n), tmp(n);
    iota(sa.begin(), sa.end(), 0);  // 初始化 sa 為 [0, 1, 2, ..., n-1]

    // 初始化 rank 為字元的 ASCII 值
    for (int i = 0; i < n; i++) {
        rank[i] = s[i];
    }

    // 倍增排序：每次比較長度為 k 的子串
    for (int k = 1; k < n; k <<= 1) {
        // 比較函數：先比較前 k 個字元，再比較後 k 個字元
        auto cmp = [&](int a, int b) {
            if (rank[a] != rank[b]) {
                return rank[a] < rank[b];
            }
            int ra = a + k < n ? rank[a + k] : -1;
            int rb = b + k < n ? rank[b + k] : -1;
            return ra < rb;
        };

        // 根據比較函數排序後綴陣列
        sort(sa.begin(), sa.end(), cmp);

        // 更新 rank：相同的後綴給相同的 rank
        tmp[sa[0]] = 0;
        for (int i = 1; i < n; i++) {
            tmp[sa[i]] = tmp[sa[i - 1]] + (cmp(sa[i - 1], sa[i]) ? 1 : 0);
        }
        rank = tmp;

        // 如果所有後綴都已區分，提前退出
        if (rank[sa[n - 1]] == n - 1) {
            break;
        }
    }
    return sa;
}
```

